package com.example.batchschedulers.repository;

import com.example.batchschedulers.model.ProductReport;
import org.springframework.data.jpa.repository.JpaRepository;
import org.springframework.stereotype.Repository;

import java.util.List;

/**
 * Spring Data JPA repository for {@link ProductReport} entities.
 *
 * <p>Provides access to report snapshots generated by the
 * {@code reportGenerationJob} batch job.
 */
@Repository
public interface ProductReportRepository extends JpaRepository<ProductReport, Long> {

    /**
     * Returns all report snapshots for a specific category, ordered by generation
     * time descending (most recent first).
     *
     * @param category the product category to filter on
     * @return list of report entries for that category
     */
    List<ProductReport> findByCategoryOrderByGeneratedAtDesc(String category);
}
